SELECT algorithm_name
  FROM encryption_algorithms
  WHERE is_block_cipher = 1 AND block_size = 256;

SELECT cipher_suite_name
FROM cipher_suites
WHERE is_deprecated = 0;

SELECT COUNT(*) AS non_deprecated_count
FROM cipher_suites
WHERE is_deprecated = 0;

SELECT method_name
FROM key_establishment_methods
WHERE method_id = 1;
